/* Animate.css Special Animations */
.animate__hinge {
  animation-name: hinge;
  transform-origin: top left;
}
.animate__jackInTheBox {
  animation-name: jackInTheBox;
}

js:
// JS Specials Trigger Logic
function triggerSpecial(aniName) {
  const el = document.getElementById('preview-box');
  el.className = 'preview-object';
  void el.offsetWidth; // Reflow
  el.classList.add('animate__animated', `animate__${aniName}`);
}
